#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use HTML::Parser;

my $cgi = CGI->new();
my $comment = $cgi->param('comment') // '';

# Sanitize the comment to allow only safe HTML tags and attributes
my $sanitized = sanitize_html($comment);

print "Content-type: text/html\n\n<div>$sanitized</div>";

sub sanitize_html {
    my ($input) = @_;

    # Define allowed tags and allowed attributes per tag
    my %allowed_tags = (
        'b'      => [],
        'i'      => [],
        'u'      => [],
        'em'     => [],
        'strong' => [],
        'p'      => [],
        'br'     => [],
        'ul'     => [],
        'ol'     => [],
        'li'     => [],
        'blockquote' => [],
        'code'   => [],
        'pre'    => [],
        'a'      => ['href', 'title'],
    );

    my $output = '';

    my $parser = HTML::Parser->new(
        api_version => 3,
        start_h => [
            sub {
                my ($tagname, $attr) = @_;
                $tagname = lc($tagname);
                if (exists $allowed_tags{$tagname}) {
                    my $tag_str = "<$tagname";
                    my $allowed_attrs = $allowed_tags{$tagname};
                    for my $allowed_attr (@$allowed_attrs) {
                        if (exists $attr->{$allowed_attr}) {
                            my $val = $attr->{$allowed_attr};
                            # For href, only allow http, https, and mailto protocols
                            if ($allowed_attr eq 'href') {
                                # Strip leading whitespace and check protocol
                                $val =~ s/^\s+//;
                                unless ($val =~ /^(?:https?:\/\/|mailto:)/i) {
                                    next;  # skip disallowed href values (blocks javascript: etc.)
                                }
                            }
                            # Encode attribute value to prevent attribute injection
                            $val = _encode_attr($val);
                            $tag_str .= qq{ $allowed_attr="$val"};
                        }
                    }
                    $tag_str .= ">";
                    $output .= $tag_str;
                }
                # Disallowed tags are silently dropped
            },
            "tagname, attr"
        ],
        end_h => [
            sub {
                my ($tagname) = @_;
                $tagname = lc($tagname);
                if (exists $allowed_tags{$tagname}) {
                    $output .= "</$tagname>";
                }
            },
            "tagname"
        ],
        text_h => [
            sub {
                my ($text) = @_;
                $output .= _encode_html($text);
            },
            "text"
        ],
        # Ignore comments, declarations, processing instructions
        comment_h => [sub {}, ""],
        declaration_h => [sub {}, ""],
        process_h => [sub {}, ""],
    );

    $parser->parse($input);
    $parser->eof();

    return $output;
}

sub _encode_html {
    my ($str) = @_;
    $str =~ s/&/&amp;/g;
    $str =~ s/</&lt;/g;
    $str =~ s/>/&gt;/g;
    $str =~ s/"/&quot;/g;
    $str =~ s/'/&#x27;/g;
    return $str;
}

sub _encode_attr {
    my ($str) = @_;
    $str =~ s/&/&amp;/g;
    $str =~ s/"/&quot;/g;
    $str =~ s/'/&#x27;/g;
    $str =~ s/</&lt;/g;
    $str =~ s/>/&gt;/g;
    return $str;
}